import datetimefrom libs.database.model import Modelfrom libs.database.types import Date, Number, Char, Date, Varchar2class BlacklistMotives(Model):    __tablename__ = 'blacklist_motives'    id = Number(field='id')    date_created = Date(field='date_created', default=datetime.datetime.now())    date_modified = Date(field='date_modified')    name = Varchar2(field='name')    key = Varchar2(field='key')    description = Varchar2(field='description')